import{_ as d,C as s,o as a,c as i,a5 as r,b as E,w as A,a as n,E as o,a4 as g,j as e}from"./chunks/framework.sOZL8giL.js";const b=JSON.parse('{"title":"让Agent拥有感官","description":"","frontmatter":{},"headers":[],"relativePath":"01-Harness工程核心原则/02-让Agent拥有感官.md","filePath":"01-Harness工程核心原则/02-让Agent拥有感官.md","lastUpdated":null}'),B={name:"01-Harness工程核心原则/02-让Agent拥有感官.md"};function p(h,t,u,C,m,c){const l=s("Mermaid");return a(),i("div",null,[t[2]||(t[2]=r('<h1 id="让agent拥有感官" tabindex="-1">让Agent拥有感官 <a class="header-anchor" href="#让agent拥有感官" aria-label="Permalink to &quot;让Agent拥有感官&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 1 模块的第 2 章。</p></blockquote><p>当代码生成速度不再是瓶颈，验证能力就成了新的瓶颈。Agent 写完代码后，怎么知道它写得对不对？OpenAI 的答案是：让 Agent 自己验证自己。但这里有一个前提——Agent 得先<strong>看得见</strong>系统的状态。</p><hr><h2 id="agent-以前是个瞎子" tabindex="-1">Agent 以前是个瞎子 <a class="header-anchor" href="#agent-以前是个瞎子" aria-label="Permalink to &quot;Agent 以前是个瞎子&quot;">​</a></h2><p>想象一个人类工程师修完 Bug 后会做什么：打开浏览器看看页面对不对、打开日志看看有没有报错、看看性能监控面板确认响应时间正常。这些动作的本质是人在用眼睛和听诊器感知系统的状态。</p><p>但以前的 Agent 不具备这些感官。它只能写代码，写完就甩手了。它看不到页面渲染成什么样，不知道系统有没有报错，更不知道性能有没有变差。需要人类验证后，截图告诉它哪里有问题。</p><p>这就是瓶颈所在：<strong>生成代码只需要几秒钟，验证代码却需要一个人类工程师。</strong></p><hr><h2 id="给-agent-装眼睛-看见-ui" tabindex="-1">给 Agent 装眼睛：看见 UI <a class="header-anchor" href="#给-agent-装眼睛-看见-ui" aria-label="Permalink to &quot;给 Agent 装眼睛：看见 UI&quot;">​</a></h2><p>OpenAI 把 Chrome 浏览器的开发者工具协议（CDP）接入了 Agent 的运行时。Agent 可以启动应用、打开页面、看到页面上每个按钮每段文字每个输入框的位置和状态。</p><p>他们还给 Agent 创建了专门的技能来处理 DOM 快照、截图和页面导航。DOM 快照就像网页的 X 光片——把网页底层的树状结构在某一刻的状态完整拍下来，交给 Agent 分析。</p><p>有了这些，Agent 能够直接复现 Bug、验证修复结果、推理 UI 的行为。以前 Agent 写完代码就结束了，现在它可以自己打开应用、自己看效果、发现不对就自己修。</p>',13)),(a(),E(g,null,{default:A(()=>[o(l,{id:"mermaid-37",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%20%E5%86%99%E4%BB%A3%E7%A0%81%5D%20--%3E%20B%5BAgent%20%E5%90%AF%E5%8A%A8%E5%BA%94%E7%94%A8%5D%0A%20%20%20%20B%20--%3E%20C%5BAgent%20%E6%89%93%E5%BC%80%E9%A1%B5%E9%9D%A2%E7%9C%8B%E6%95%88%E6%9E%9C%5D%0A%20%20%20%20C%20--%3E%20D%5BAgent%20%E6%A3%80%E6%9F%A5%E6%97%A5%E5%BF%97%E5%92%8C%E6%8C%87%E6%A0%87%5D%0A%20%20%20%20D%20--%3E%20E%7B%E5%8F%91%E7%8E%B0%E9%97%AE%E9%A2%98%EF%BC%9F%7D%0A%20%20%20%20E%20--%3E%7C%E6%98%AF%7C%20F%5BAgent%20%E4%BF%AE%E5%A4%8D%E4%BB%A3%E7%A0%81%5D%0A%20%20%20%20F%20--%3E%20B%0A%20%20%20%20E%20--%3E%7C%E5%90%A6%7C%20G%5B%E4%BB%BB%E5%8A%A1%E5%AE%8C%E6%88%90%5D%0A%20%20%20%20G%20--%3E%20H%5B%E5%BC%80%E5%90%AF%20PR%5D%0A%20%20%20%20H%20--%3E%20I%5BAgent%20%E8%87%AA%E6%88%91%E5%AE%A1%E6%9F%A5%20%2B%20%E4%BA%A4%E5%8F%89%E5%AE%A1%E6%9F%A5%5D%0A%20%20%20%20I%20--%3E%20J%5B%E8%87%AA%E5%8A%A8%E5%90%88%E5%B9%B6%5D%0A"})]),fallback:A(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=r('<blockquote><p>💡 <strong>图解：</strong> 有了感官的 Agent 形成了&quot;编码→验证→修复&quot;的自主闭环，人类工程师彻底退出执行环节。</p></blockquote><hr><h2 id="给-agent-装听诊器-看见系统内部" tabindex="-1">给 Agent 装听诊器：看见系统内部 <a class="header-anchor" href="#给-agent-装听诊器-看见系统内部" aria-label="Permalink to &quot;给 Agent 装听诊器：看见系统内部&quot;">​</a></h2><p>光看 UI 还不够。OpenAI 对可观测性工具做了同样的改造——日志、指标、链路追踪，这三件套让 Agent 能感知肉眼看不到的系统内部状态。</p><p>他们给每个 Agent 任务搭建了一套临时的可观测性环境，每个任务有自己独立的日志和指标，用完就销毁。就像给每个 Agent 配了一间隔音室——它看到的日志只属于自己这个任务，不会被其他并行任务的信息干扰。</p><p>Agent 可以用 LogQL 在海量日志里精确搜索某一条错误记录，用 PromQL 查询&quot;最近五分钟的平均响应时间是多少&quot;。以前这些约束不容易被 Agent 验证，需要靠人类盯着监控面板去看。<strong>现在 Agent 自己就能查，就能判断，就能通过或者打回。</strong></p><hr><h2 id="给-agent-一张地图-知识可发现" tabindex="-1">给 Agent 一张地图：知识可发现 <a class="header-anchor" href="#给-agent-一张地图-知识可发现" aria-label="Permalink to &quot;给 Agent 一张地图：知识可发现&quot;">​</a></h2><p>光有感官还不够，Agent 还需要知道去哪里找信息。OpenAI 的解法是：<strong>给 Codex 一张地图，而不是一本一千页的说明书。</strong></p><p>他们一开始试了一个巨型 <code>agents.md</code> 方案，把所有规则全塞进一个超长文件里，结果以完全可预见的方式失败了：</p><ul><li><strong>上下文是稀缺资源</strong>——巨大的指令文件会挤占任务本身代码的空间</li><li><strong>指导太多等于没有指导</strong>——当所有东西都被标记为重要时，什么都不重要</li><li><strong>它会立即腐烂</strong>——巨型说明文件会变成过时规则的坟场</li></ul><p>正确做法是把 <code>agents.md</code> 当目录——一百行的目录，指向 <code>dox/</code> 目录里的具体文档。Agent 从一个小的、稳定的起点开始，然后被告知接下来该去哪里找信息，而不是一上来就被淹没。</p><p>知识得先在仓库里。从 Agent 的视角来看，任何它在运行时无法在上下文中访问的东西，实际上就不存在。Slack 频道里的讨论、Google Docs 里的方案、同事脑子里的 API 坑——对 Agent 来说都是黑洞。Agent 能看到的现实世界，只有仓库里的版本化文件。</p><hr><h2 id="把建议变成法律-强制执行" tabindex="-1">把建议变成法律：强制执行 <a class="header-anchor" href="#把建议变成法律-强制执行" aria-label="Permalink to &quot;把建议变成法律：强制执行&quot;">​</a></h2><p>有了眼睛和地图，Agent 还需要约束。当 AI 接管了写代码这件事，如何保证它不会以光速造出一座屎山？</p><p>OpenAI 的思路：<strong>严格的约束</strong>。约束是速度的前提。边界必须刚性封死，但边界之内让 Agent 完全自由地实现。</p><p>文档是建议，Agent 需要的是法律。如果规则只是写在文档里，Agent 会复制已有结构、放大已有模式，错误结构会被指数级复制。所以必须把建议变成法律——通过自定义 Linter 机械执行。</p><p>这里有一个精妙的设计：<strong>Linter 不只是报错工具，它们是上下文注入工具。</strong> 当 Linter 报错时，错误信息里会直接写上补救指令。Agent 读到这条报错，等于读到了一条 Prompt，然后它自己重构代码，重新跑 Linter，直到全部变绿。</p><p>同一条规则，在人类世界是负担，在 Agent 世界是杠杆。一旦你把一条规则写进代码，它瞬间就在所有 Agent 的所有任务中生效。</p><hr><h2 id="投资回报率-6-小时的自主工作" tabindex="-1">投资回报率：6 小时的自主工作 <a class="header-anchor" href="#投资回报率-6-小时的自主工作" aria-label="Permalink to &quot;投资回报率：6 小时的自主工作&quot;">​</a></h2><p>给 Agent 装眼睛和听诊器带来的最终效果是什么？单次 Codex 在一个任务上工作经常超过 6 个小时，通常是在人类睡觉的时候。</p><p>因为 Agent 有了感官和地图，它可以自主地：写代码 → 看效果 → 查日志 → 发现问题 → 修复 → 再验证，循环直到通过，完全不需要人类介入。</p><p><strong>状态可读，让 Agent 能看见 UI、感知系统内部状态，从而实现闭环自主工作。</strong></p><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">把所有规则塞进一个巨型 <code>agents.md</code> 文件</td><td style="text-align:left;">用 100 行 <code>agents.md</code> 做目录，指向 <code>dox/</code> 具体文档</td><td style="text-align:left;">巨型文件挤占上下文空间、指导太多等于没有、立即腐烂变成过时规则坟场</td></tr><tr><td style="text-align:left;">知识散落在 Slack、Google Docs、同事脑子里</td><td style="text-align:left;">把重要知识搬进仓库，版本化管理</td><td style="text-align:left;">Agent 运行时无法访问的东西，对它来说就不存在——它只看得见仓库里的文件</td></tr><tr><td style="text-align:left;">用建议文档约束 Agent 行为</td><td style="text-align:left;">通过自定义 Linter 机械执行规则</td><td style="text-align:left;">文档是建议，Agent 会复制已有结构放大错误；Linter 报错自带修复指令，等同于 Prompt</td></tr><tr><td style="text-align:left;">Agent 写完代码就甩手，不给它验证手段</td><td style="text-align:left;">接入 CDP、LogQL/PromQL，让 Agent 自己看到系统状态</td><td style="text-align:left;">生成代码只需几秒，验证却需要人类——瓶颈不在模型智商，而在环境定义不足</td></tr><tr><td style="text-align:left;">让 Agent 盲目探索仓库结构</td><td style="text-align:left;">提供 <code>architecture.md</code> 鸟瞰图 + 结构化目录</td><td style="text-align:left;">Agent 自行搜索路径本身是高错误率环节，会浪费大量 Token 在无效探索上</td></tr></tbody></table><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>状态可读三层含义：可见（CDP）、可解析（LogQL/PromQL）、可验证（闭环反馈）</li><li>知识可发现：一张地图而非一本说明书，知识必须在仓库里</li><li>强制执行：Linter 即 Prompt，规则是倍增器</li><li>投资仓库可读性是一次投入，多个 Agent 同时受益</li><li>约束的三级火箭：建议 → 文档 → 代码</li></ul>',31)),(a(),E(g,null,{default:A(()=>[o(l,{id:"mermaid-228",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%E5%BB%BA%E8%AE%AE%3Cbr%2F%3E%E5%9B%A2%E9%98%9F%E7%BA%A6%E5%AE%9A%3Cbr%2F%3ECode%20Review%E6%8F%90%E9%86%92%5D%20--%3E%7C%E7%BA%A6%E6%9D%9F%E5%8A%9B%E5%BC%B1%3Cbr%2F%3E%E6%98%93%E8%A2%AB%E5%BF%BD%E7%95%A5%7C%20B%5B%E6%96%87%E6%A1%A3%3Cbr%2F%3E%E6%9E%B6%E6%9E%84%E6%96%87%E6%A1%A3%3Cbr%2F%3E%E7%BC%96%E7%A0%81%E8%A7%84%E8%8C%83%5D%0A%20%20%20%20B%20--%3E%7C%E7%BA%A6%E6%9D%9F%E5%8A%9B%E4%B8%AD%3Cbr%2F%3E%E4%BE%9D%E8%B5%96%E4%BA%BA%E5%B7%A5%E6%89%A7%E8%A1%8C%7C%20C%5B%E4%BB%A3%E7%A0%81%3Cbr%2F%3E%E8%87%AA%E5%AE%9A%E4%B9%89Linter%3Cbr%2F%3E%E8%87%AA%E5%8A%A8%E5%BC%BA%E5%88%B6%E6%89%A7%E8%A1%8C%5D%0A%20%20%20%20C%20--%3E%7C%E7%BA%A6%E6%9D%9F%E5%8A%9B%E6%9C%80%E5%BC%BA%3Cbr%2F%3E%E7%9E%AC%E9%97%B4%E5%85%A8%E9%87%8F%E7%94%9F%E6%95%88%7C%20D%5BAgent%20%E7%A8%B3%E5%AE%9A%E4%BA%A7%E5%87%BA%5D%0A"})]),fallback:A(()=>[...t[1]||(t[1]=[n(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=e("blockquote",null,[e("p",null,[n("💡 "),e("strong",null,"图解："),n(" 约束力逐级递增——Linter 报错本身就是一条 Prompt，Agent 读完自己修，规则瞬间在所有 Agent 中生效。")])],-1)),t[5]||(t[5]=e("hr",null,null,-1)),t[6]||(t[6]=e("p",null,[e("strong",null,"上一章"),n(": "),e("a",{href:"./01-范式转移.html"},"范式转移"),n(" | "),e("strong",null,"下一章"),n(": "),e("a",{href:"./03-成本、自主与熵增.html"},"成本、自主与熵增")],-1))])}const x=d(B,[["render",p]]);export{b as __pageData,x as default};
